import{_ as t,o as r,c as i,ai as a}from"./chunks/framework.CaiDwmc7.js";const u=JSON.parse(`{"title":"Behavioral Principles","description":"The five key behavioral constraints enforced through Prism's prompt engineering.","frontmatter":{"title":"Behavioral Principles","description":"The five key behavioral constraints enforced through Prism's prompt engineering.","outline":[2,3]},"headers":[],"relativePath":"plugin/behavioral-principles.md","filePath":"plugin/behavioral-principles.md","lastUpdated":1772487797000}`),o={name:"plugin/behavioral-principles.md"};function n(s,e,l,c,d,h){return r(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="behavioral-principles" tabindex="-1">Behavioral Principles <a class="header-anchor" href="#behavioral-principles" aria-label="Permalink to “Behavioral Principles”">​</a></h1><p>The plugin enforces several key behavioral constraints through its prompt engineering:</p><h2 id="_1-documentarian-not-critic" tabindex="-1">1. &quot;Documentarian, Not Critic&quot; <a class="header-anchor" href="#_1-documentarian-not-critic" aria-label="Permalink to “1. &quot;Documentarian, Not Critic&quot;”">​</a></h2><p>All research agents are instructed to <strong>only describe what exists</strong>. They do NOT:</p><ul><li>Suggest improvements</li><li>Critique implementation choices</li><li>Perform root cause analysis (unless explicitly asked)</li><li>Recommend refactoring</li></ul><p>This prevents research from becoming opinionated, ensuring clean separation between observation (research phase) and decision-making (plan phase).</p><h2 id="_2-interactive-planning" tabindex="-1">2. Interactive Planning <a class="header-anchor" href="#_2-interactive-planning" aria-label="Permalink to “2. Interactive Planning”">​</a></h2><p>Plans are contracts, not suggestions. The planning process:</p><ol><li>Present understanding of the codebase first</li><li>Get user buy-in before proceeding</li><li>Iterate on each section with feedback</li><li>Never write a full plan in one shot</li><li>Resolve all unknowns before finalizing</li><li>Always separate &quot;Automated Verification&quot; (runnable commands) from &quot;Manual Verification&quot; (human testing)</li></ol><h2 id="_3-fresh-context-per-iteration" tabindex="-1">3. Fresh Context Per Iteration <a class="header-anchor" href="#_3-fresh-context-per-iteration" aria-label="Permalink to “3. Fresh Context Per Iteration”">​</a></h2><p>Spectrum gives each story a fresh Claude session via <code>spectrum.sh</code>. Memory persists through:</p><ul><li><code>stories.json</code> (status, steps, commit hashes)</li><li><code>progress.md</code> (accumulated learnings)</li><li>Git commits (the actual work)</li></ul><p>This prevents context window degradation across long-running autonomous execution.</p><h2 id="_4-two-category-success-criteria" tabindex="-1">4. Two-Category Success Criteria <a class="header-anchor" href="#_4-two-category-success-criteria" aria-label="Permalink to “4. Two-Category Success Criteria”">​</a></h2><p>Every plan separates verification into:</p><table tabindex="0"><thead><tr><th>Category</th><th>Examples</th><th>Runner</th></tr></thead><tbody><tr><td><strong>Automated Verification</strong></td><td><code>npm test</code>, <code>npm run typecheck</code>, <code>npm run lint</code></td><td>Claude / Spectrum</td></tr><tr><td><strong>Manual Verification</strong></td><td>&quot;Click the login button and verify redirect&quot;</td><td>Human tester</td></tr></tbody></table><h2 id="_5-signal-protocol" tabindex="-1">5. Signal Protocol <a class="header-anchor" href="#_5-signal-protocol" aria-label="Permalink to “5. Signal Protocol”">​</a></h2><p>Autonomous execution uses XML-like signals for flow control:</p><table tabindex="0"><thead><tr><th>Signal</th><th>Tag</th><th>Meaning</th></tr></thead><tbody><tr><td>Complete</td><td><code>&lt;promise&gt;COMPLETE&lt;/promise&gt;</code></td><td>Story finished successfully</td></tr><tr><td>Continue</td><td><code>&lt;spectrum-continue&gt;</code></td><td>Success, schedule next iteration</td></tr><tr><td>Retry</td><td><code>&lt;spectrum-retry reason=&quot;...&quot;&gt;</code></td><td>Transient failure, retry</td></tr><tr><td>Blocked</td><td><code>&lt;spectrum-blocked reason=&quot;...&quot;&gt;</code></td><td>Cannot proceed, skip</td></tr><tr><td>Error</td><td><code>&lt;spectrum-error reason=&quot;...&quot;&gt;</code></td><td>Fatal error, stop</td></tr></tbody></table>',19)])])}const g=t(o,[["render",n]]);export{u as __pageData,g as default};
